**C++ Program: Dictionary Using Binary Search Tree (BST)**

This program implements a dictionary using a Binary Search Tree (BST) data structure. It allows users to insert words and definitions, search for words, delete words, and display the entire dictionary.

---

### ✅ **Features:**
- Insert words and definitions.
- Search for a word and display its definition.
- Delete a word and its definition.
- Display all words and their definitions.

---

### 🧠 **Implementation Overview:**

1. **BST Node Structure:** Each node contains a word, a definition, and pointers to left and right children.
2. **BST Operations:**
   - Insertion
   - Search
   - Deletion
3. **User Interface:** A simple CLI interface for input and output.

---

### 🧩 **Code:**

```cpp
#include <iostream>
#include <string>
#include <map>
#include <vector>
#include <algorithm>

using namespace std;

struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

class Dictionary {
public:
    Node* root = nullptr;

    void insert(string word, string definition) {
        root = insertRec(root, word, definition);
    }

    Node* insertRec(Node* root, string word, string definition) {
        if (root == nullptr) {
            return new Node(word, definition);
        }

        if (word < root->word) {
            root->left = insertRec(root->left, word, definition);
        } else if (word > root->word) {
            root->right = insertRec(root->right, word, definition);
        }

        return root;
    }

    bool search(string word) {
        return searchRec(root, word);
    }

    bool searchRec(Node* node, string word) {
        if (node == nullptr) return false;
        if (node->word == word) return true;
        if (word < node->word) return searchRec(node->left, word);
        else return searchRec(node->right, word);
    }

    void deleteWord(string word) {
        root = deleteRec(root, word);
    }

    Node* deleteRec(Node* root, string word) {
        if (root == nullptr) return root;

        if (word < root->word) {
            root->left = deleteRec(root->left, word);
        } else if (word > root->word) {
            root->right = deleteRec(root->right, word);
        } else {
            if (root->left == nullptr) {
                Node* temp = root->right;
                delete root;
                root = temp;
            } else if (root->right == nullptr) {
                Node* temp = root->left;
                delete root;
                root = temp;
            } else {
                Node* temp = getSuccessor(root);
                root->word = temp->word;
                root->definition = temp->definition;
                root->left = deleteRec(root->left, temp->word);
            }
        }
        return root;
    }

    Node* getSuccessor(Node* node) {
        Node* successor = node->right;
        while (successor->left != nullptr) {
            successor = successor->left;
        }
        return successor;
    }

    void displayAll() {
        displayRec(root);
    }

    void displayRec(Node* node) {
        if (node != nullptr) {
            displayRec(node->left);
            cout << node->word << " : " << node->definition << endl;
            displayRec(node->right);
        }
    }
};

int main() {
    Dictionary dict;
    string word, definition;

    cout << "Welcome to the Dictionary Application!\n";
    cout << "Enter words and their definitions (type 'exit' to quit):\n";

    while (true) {
        cout << "> ";
        getline(cin, word);
        if (word == "exit") break;

        cout << "Enter definition: ";
        getline(cin, definition);

        dict.insert(word, definition);
    }

    cout << "\nDictionary Display:\n";
    dict.displayAll();

    cout << "\nSearch for a word: ";
    getline(cin, word);
    if (dict.search(word)) {
        cout << "Definition of " << word << " is: " << endl;
    } else {
        cout << "Word not found in the dictionary.\n";
    }

    cout << "\nDelete a word: ";
    getline(cin, word);
    if (dict.search(word)) {
        dict.deleteWord(word);
        cout << "Word " << word << " deleted successfully.\n";
    } else {
        cout << "Word not found in the dictionary.\n";
    }

    return 0;
}
```

---

### 📌 **How to Use:**
1. Compile the code with a C++ compiler (e.g., `g++ -o dict dict.cpp`).
2. Run the program and enter words and definitions.
3. Use the CLI to search, delete, and display the dictionary.

---

This program is a robust and efficient way to manage a dictionary using a BST, with clear user interaction and formatting. 🌟

