**C++ Program for Dictionary Using Binary Search Tree**

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

using namespace std;

// Node structure for the BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST operations
class BinarySearchTree {
public:
    BinarySearchTree() : root(nullptr) {}

    void insert(string word, string definition) {
        root = insertNode(root, word, definition);
    }

    Node* insertNode(Node* node, string word, string definition) {
        if (node == nullptr) {
            return new Node(word, definition);
        }

        if (word < node->word) {
            node->right = insertNode(node->right, word, definition);
        } else {
            node->left = insertNode(node->left, word, definition);
        }

        return node;
    }

    bool search(string word) {
        return searchNode(root, word);
    }

    bool searchNode(Node* node, string word) {
        if (node == nullptr) return false;
        if (node->word == word) return true;
        return searchNode(node->left, word) || searchNode(node->right, word);
    }

    void deleteNode(string word) {
        root = deleteNodeRecursive(root, word);
    }

    Node* deleteNodeRecursive(Node* node, string word) {
        if (node == nullptr) return node;

        if (word < node->word) {
            node->left = deleteNodeRecursive(node->left, word);
        } else if (word > node->word) {
            node->right = deleteNodeRecursive(node->right, word);
        } else {
            // Node found, delete
            if (node->left == nullptr) {
                return node->right;
            } else if (node->right == nullptr) {
                return node->left;
            } else {
                // Node has two children: find the inorder successor
                Node* successor = getInorderSuccessor(node->right);
                node->word = successor->word;
                node->definition = successor->definition;

                node->right = deleteNodeRecursive(node->right, successor->word);
            }
        }

        return node;
    }

    Node* getInorderSuccessor(Node* node) {
        Node* successor = node->right;
        while (successor->left != nullptr) {
            successor = successor->left;
        }
        return successor;
    }

    void printAll() {
        printInorder(root);
    }

    void printInorder(Node* node) {
        if (node != nullptr) {
            printInorder(node->left);
            cout << node->word << " : " << node->definition << endl;
            printInorder(node->right);
        }
    }
};

int main() {
    BinarySearchTree dict;

    string word, definition;
    cout << "Welcome to the Dictionary Program using Binary Search Tree!\n";
    cout << "Enter words and their definitions one by one:\n";

    while (true) {
        cout << "Enter a word (or type 'exit' to quit): ";
        cin >> word;
        if (word == "exit") break;

        cout << "Enter the definition: ";
        cin >> definition;

        dict.insert(word, definition);
    }

    cout << "\nDictionary Entries:\n";
    dict.printAll();

    cout << "\nSearch for a word: ";
    cin >> word;
    if (dict.search(word)) {
        cout << "Definition: " << word << " : " << dict.word << endl;
    } else {
        cout << "Word not found in the dictionary.\n";
    }

    cout << "\nDelete a word: ";
    cin >> word;
    if (dict.search(word)) {
        dict.deleteNode(word);
        cout << "Word and its definition deleted.\n";
    } else {
        cout << "Word not found in the dictionary.\n";
    }

    cout << "\nFinal Dictionary Entries:\n";
    dict.printAll();

    return 0;
}
```

### Features:
1. **Insertion**: Words and definitions are added to the BST.
2. **Search**: Users can look up a word by entering it.
3. **Deletion**: A word and its definition are removed from the dictionary.
4. **Display**: The entire dictionary is printed in alphabetical order.

### Notes:
- The BST is implemented with basic operations like insertion, search, deletion, and traversal.
- The program uses an in-order traversal to print entries in alphabetical order.
- Input validation is minimal; the user can type "exit" to terminate the program.

This implementation provides a clean, organized way to manage a dictionary using a binary search tree, with user-friendly input and output.

