```cpp
#include <iostream>
#include <limits>
#include <string>

using namespace std;

// Function to get a valid numeric input from the user
double getValidInput(string prompt) {
    double value;
    cout << prompt << " (Enter a number): ";
    while (true) {
        cin >> value;
        if (cin.fail()) {
            cout << "Invalid input. Please enter a valid number.\n";
            cin.clear();
            cin.ignore(numeric_limits<streamsize>::max(), '\n');
        } else {
            break;
        }
    }
    return value;
}

int main() {
    // Display instructions to the user
    cout << "Please enter two numbers to calculate their sum.\n";

    // Get input from the user
    double num1 = getValidInput("First number: ");
    double num2 = getValidInput("Second number: ");

    // Calculate the sum
    double sum = num1 + num2;

    // Display the result
    cout << "\nThe sum of " << num1 << " and " << num2 << " is: " << sum << endl;

    return 0;
}
```

---

### Explanation:

- **Input Validation:** The `getValidInput` function ensures the user enters a valid numeric value. If not, it prompts again.
