- Use **Windows Forms** or **WPF** for the UI.
- Implement controls like `TextBox`, `DataGridView`, `Chart`, and `Button`.

### **2. Core Logic**
```csharp
public class GolfRound
{
    public int TotalHoles { get; set; }
    public int[] ParValues { get; set; }
    public int[] Scores { get; set; }

    public GolfRound(int totalHoles, int[] parValues, int[] scores)
    {
        TotalHoles = totalHoles;
        ParValues = parValues;
        Scores = scores;
    }

    public int CalculateTotalScore()
    {
        return Scores.Sum();
    }

    public int CalculateTotalPar()
    {
        return ParValues.Sum();
    }
}
```

### **3. Score Analysis**
```csharp
public class ScoreAnalysis
{
    public int TotalHoles { get; set; }
    public int TotalPar { get; set; }
    public int TotalScore { get; set; }
    public int[] HoleScores { get; set; }
    public int[] HoleDiffs { get; set; }

    public ScoreAnalysis(GolfRound round)
    {
        TotalHoles = round.TotalHoles;
        TotalPar = round.CalculateTotalPar();
        TotalScore = round.CalculateTotalScore();
        HoleScores = round.Scores;
        HoleDiffs = new int[TotalHoles];
        for (int i = 0; i < TotalHoles; i++)
        {
            HoleDiffs[i] = HoleScores[i] - round.ParValues[i];
        }
    }

    public void DisplayStats()
    {
        Console.WriteLine($"Total Holes: {TotalHoles}");
        Console.WriteLine($"Total Par: {TotalPar}");
        Console.WriteLine($"Total Score: {TotalScore}");
        Console.WriteLine("\nHole Scores and Differences:");
        for (int i = 0; i < TotalHoles; i++)
        {
            Console.WriteLine($"Hole {i + 1}: Score {HoleScores[i]} | Par {ParValues[i]} | Diff {HoleDiffs[i]}");
        }
    }
}
```

