### Java Code

```java
import java.awt.image.BufferedImage;
import java.awt.image.BufferedImageOp;
import java.awt.image.ConvolveOp;
import java.awt.image.Kernel;
import java.awt.image.ImageFilter;
import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.net.URL;
import javax.imageio.ImageIO;

public class ImageFilterDownloader {

    public static void main(String[] args) {
        String imageUrl = "https://example.com/sample-image.jpg"; // Replace with your image URL
        String outputFilePath = "processed_image.jpg";

        try {
            BufferedImage originalImage = downloadAndLoadImage(imageUrl);
            BufferedImage filteredImage = applyFilter(originalImage);
            saveImage(filteredImage, outputFilePath);
            System.out.println("Image saved to: " + outputFilePath);
        } catch (IOException e) {
            System.err.println("Error during image processing: " + e.getMessage());
        }
    }

    private static BufferedImage downloadAndLoadImage(String imageUrl) throws IOException {
        URL url = new URL(imageUrl);
        BufferedImage image = ImageIO.read(url);
        return image;
    }

    private static BufferedImage applyFilter(BufferedImage image) {
        // Apply grayscale filter
        BufferedImage grayscaleImage = new BufferedImage(image.getWidth(), image.getHeight(), BufferedImage.TYPE_INT_RGB);
        Graphics2D g2d = grayscaleImage.createGraphics();
        g2d.drawImage(image, 0, 0, null);
        g2d.dispose();

        // Grayscale filter
        Kernel kernel = new Kernel(3, 3, new int[]{1, 1, 1, 1, 0, 0, 1, 1, 1});
        ConvolveOp convolveOp = new ConvolveOp(kernel, ConvolveOp.OP_ADD, null);
        ImageFilter filter = convolveOp;

        BufferedImage filteredImage = new BufferedImage(image.getWidth(), image.getHeight(), image.getType());
        g2d = filteredImage.createGraphics();
        g2d.drawImage(image, 0, 0, null);
        g2d.drawImage(filter, 0, 0, null);
        g2d.dispose();

        return filteredImage;
    }

    private static void saveImage(BufferedImage image, String outputPath) throws IOException {
        ImageIO.write(image, "jpg", new File(outputPath));
    }
}
```

---

### Notes:

- **Filter Implementation**:
  - This example uses a `ConvolveOp` with a kernel for a basic grayscale effect. You can extend this with more sophisticated filters (e.g., blur, contrast, etc.) as needed.

- **Image Format**:
