### ✅ Script: `haversine_distance.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON;

# Script: haversine_distance.pl
# Author: [Your Name]
# Description: Calculate the distance between two points using Haversine formula.

# Configuration
my $km_output = 1;  # 1 for kilometers, 2 for miles
my $debug = 0;

# Main function
sub calculate_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;

    # Validate inputs
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Error: All coordinates are required.\n";
    }

    if (!is_valid_coordinate($lat1) || !is_valid_coordinate($lon1) || !is_valid_coordinate($lat2) || !is_valid_coordinate($lon2)) {
        die "Error: Invalid coordinate format. Please use numbers with degrees and minutes (e.g., 40.7128, -74.0060).\n";
    }

    # Convert degrees to radians
    my $lat1_rad = radian_to_rad($lat1);
    my $lon1_rad = radian_to_rad($lon1);
    my $lat2_rad = radian_to_rad($lat2);
    my $lon2_rad = radian_to_rad($lon2);

    # Haversine formula
    my $a = (sin($lat1_rad - $lat2_rad) ** 2 + cos($lat1_rad) * cos($lat2_rad) * sin($lon1_rad - $lon2_rad) ** 2);
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = 6371 * $c; # Earth radius in km

    return $distance;
}

