This Perl script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs, handles errors, and provides results in kilometers or miles.

## Features:
- **Input Handling**: Accepts latitude and longitude for two locations.
- **Haversine Formula**: Computes the distance using spherical geometry.
- **Error Handling**: Validates inputs and handles invalid data.
- **Output**: Displays location names, distance in kilometers or miles.
- **Tests**: Includes sample inputs and outputs for verification.

---

### Perl Script: `haversine_distance.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use JSON::PP;

# Script to calculate distance between two points using Haversine formula
# Author: [Your Name]
# Date: [Date]

# Configuration
my $km_output = 1;  # 1 = kilometers, 2 = miles
my $location_names = 1;  # 1 = display location names, 0 = only distance

# Haversine formula
sub haversine {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371;  # Radius of Earth in kilometers

    my $dlat = radians($lat2 - $lat1);
    my $dlong = radians($lon2 - $lat2);

    my $a = sin($dlat/2) ** 2 + cos($lat1) * cos($lat2) * sin($dlong/2) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Convert degrees to radians
sub radians {
    return $_[0] * pi / 180;
}

# Load location names from a JSON file
sub load_location_names {
    my $file = 'locations.json';
    my $json = read_file($file);
    return $json ? decode_json($json) : {};
}

sub read_file {
    my ($file) = @_;
    open(my $fh, '<', $file) or die "Cannot open $file: $!";
    my $content = do { local $/; <$fh> };
    close $fh;
    return $content;
}

# Main function
sub main {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $distance;
    my $unit = 'km';

    # Validate inputs
    if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
        die "Please provide valid latitude and longitude for both locations.\n";
    }

    # Check if the coordinates are numeric
    if (!($lat1 =~ /^-?\d+\.?\d*$/) || !($lon1 =~ /^-?\d+\.?\d*$/) || 
        !($lat2 =~ /^-?\d+\.?\d*$/) || !($lon2 =~ /^-?\d+\.?\d*$/)) {
        die "Latitude and longitude must be numeric.\n";
    }

    # Compute distance
    $distance = haversine($lat1, $lon1, $lat2, $lon2);

    # Decide unit
    if ($km_output == 1) {
