**Binary Search Tree (BST) Implementation in Swift**

Below is a clean and efficient Swift implementation of a Binary Search Tree with insertion, deletion, and traversal functions. The BST maintains the standard properties of a binary search tree:

- **Left subtree contains only less than the node**
- **Right subtree contains only greater than the node**

### ✅ Features:
- **Insertion** - Adds nodes in the correct position.
- **Deletion** - Removes nodes while maintaining BST properties.
- **Traversal** - Supports pre-order, in-order, and post-order traversal.

---

### 🧠 Implementation Details

- **Node struct**: Represents each node in the BST with `value`, `left`, and `right` properties.
- **BST class**: Contains methods for insertion, deletion, and traversal.
- **Traversals**:
  - **Pre-order**: Visit node, then left, then right.
  - **In-order**: Left, visit node, right.
  - **Post-order**: Left, right, visit node.

---

### 🧾 Swift Code

```swift
import Foundation

// Node structure for Binary Search Tree
struct Node<T> {
    let value: T
    var left: Node<T>?
    var right: Node<T>?

    init(_ value: T) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Binary Search Tree class
class BST<T> {
    var root: Node<T>?

    // Insert a new node into the BST
    func insert(_ value: T) {
        root = insertNode(root, value)
    }

    private func insertNode(_ node: Node<T>?, _ value: T) -> Node<T> {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: T) {
        root = deleteNode(root, value)
    }

    private func deleteNode(_ node: Node<T>?, _ value: T) -> Node<T> {
        guard let node = node else { return nil }

        if value < node.value {
            node.left = deleteNode(node.left, value)
        } else if value > node.value {
            node.right = deleteNode(node.right, value)
        } else {
            // Node found, delete it
            if node.left == nil {
                return node.right
            } else if node.right == nil {
                return node.left
            } else {
                // Node has two children; find the in-order successor
                let successor = findInOrderSuccessor(node)
                node.value = successor.value
                node.right = deleteNode(node.right, successor.value)
            }
        }

        return node
    }

    // Find the in-order successor
    private func findInOrderSuccessor(_ node: Node<T>) -> Node<T> {
        var current = node.right
        while current != nil {
            let next = current!.left
            if next != nil {
                // Found a node with left child (not null)
                current = next
            } else {
                // No left child; current is the successor
                return current!
            }
        }
        return current!
    }

    // Traversal functions
    func preOrderTraverse() -> [T] {
        var result = [T]()
        preOrderTraverse(root, &result)
        return result
    }

    private func preOrderTraverse(_ node: Node<T>?, _ result: inout [T]) {
        if let node = node {
            result.append(node.value)
            preOrderTraverse(node.left, &result)
            preOrderTraverse(node.right, &result)
        }
    }

    func inOrderTraverse() -> [T] {
        var result = [T]()
        inOrderTraverse(root, &result)
        return result
    }

    private func inOrderTraverse(_ node: Node<T>?, _ result: inout [T]) {
        if let node = node {
            inOrderTraverse(node.left, &result)
            result.append(node.value)
            inOrderTraverse(node.right, &result)
        }
    }

    func postOrderTraverse() -> [T] {
        var result = [T]()
        postOrderTraverse(root, &result)
        return result
    }

    private func postOrderTraverse(_ node: Node<T>?, _ result: inout [T]) {
        if let node = node {
            postOrderTraverse(node.left, &result)
            postOrderTraverse(node.right, &result)
            result.append(node.value)
        }
    }
}
```

---

### 📝 Usage Example

```swift
let bst = BST<Int>()
bst.insert(5)
bst.insert(3)
bst.insert(7)
bst.insert(1)
bst.insert(9)

print("Pre-order traversal: ", bst.preOrderTraverse())
print("In-order traversal: ", bst.inOrderTraverse())
print("Post-order traversal: ", bst.postOrderTraverse())

bst.delete(3)
print("After deleting 3: ")
print("Pre-order: ", bst.preOrderTraverse())
print("In-order: ", bst.inOrderTraverse())
print("Post-order: ", bst.postOrderTraverse())
```

---

This implementation ensures efficient insertion, deletion, and traversal operations with time complexity of **O(log n)** for insert/delete and **O(n)** for traversal in the worst case (for a skewed tree). The code is clean, well-structured, and easy to understand.

