**Binary Search Tree Implementation in Swift**

Here's a clean and efficient Swift implementation of a Binary Search Tree (BST) with insertion, deletion, and traversal functions. The BST maintains the standard properties of a binary search tree, and the traversal functions support pre-order, in-order, and post-order.

```swift
import Foundation

// Define the Node structure for the BST
struct Node {
    var value: Int
    var left: Node?
    var right: Node?

    init(_ value: Int) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define the BST class
class BinarySearchTree {
    var root: Node?

    // Insert a new value into the BST
    func insert(_ value: Int) {
        root = insertNode(root, value)
    }

    // Helper function to insert a node into the BST
    private func insertNode(_ node: Node?, _ value: Int) -> Node? {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else if value > node!.value {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: Int) {
        root = deleteNode(root, value)
    }

    // Helper function to delete a node
    private func deleteNode(_ node: Node?, _ value: Int) -> Node? {
        guard let node = node else { return nil }

        if value < node.value {
            node.left = deleteNode(node.left, value)
        } else if value > node.value {
            node.right = deleteNode(node.right, value)
        } else {
            // Node found, perform deletion
            if node.left == nil {
                return node.right
            } else if node.right == nil {
                return node.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findMin(node.right!)
                let temp = Node(successor.value)
                temp.left = node.left!

                // Copy the right subtree of the predecessor to the node
                node.left = temp
                node.right = deleteNode(node.right, successor.value)
            }
        }

        return node
    }

    // Find the minimum value in the subtree rooted at 'node'
    private func findMin(_ node: Node?) -> Int {
        var current = node
        while current?.left != nil {
            current = current!.left
        }
        return current!.value
    }

    // Traversal functions
    // Pre-order traversal: visit node, then left, then right
    func preOrderTraverse() {
        preOrderTraverse(root, nil)
    }

    private func preOrderTraverse(_ node: Node?, _ parent: Node?) -> Void {
        if let node = node {
            print("Pre-order: $node.value")
            preOrderTraverse(node.left, node)
            preOrderTraverse(node.right, node)
        }
    }

    // In-order traversal: left, visit node, right
    func inOrderTraverse() {
        inOrderTraverse(root, nil)
    }

    private func inOrderTraverse(_ node: Node?, _ parent: Node?) -> Void {
        if let node = node {
            inOrderTraverse(node.left, node)
            print("In-order: $node.value")
            inOrderTraverse(node.right, node)
        }
    }

    // Post-order traversal: left, right, visit node
    func postOrderTraverse() {
        postOrderTraverse(root, nil)
    }

    private func postOrderTraverse(_ node: Node?, _ parent: Node?) -> Void {
        if let node = node {
            postOrderTraverse(node.left, node)
            postOrderTraverse(node.right, node)
            print("Post-order: $node.value")
        }
    }
}
```

### Explanation:

- **Node Structure**: Each node contains a value and pointers to left and right children.
- **Insertion**: The `insert` method adds a new node by comparing values and moving left or right as appropriate.
- **Deletion**: The `delete` method handles various cases, including:
  - A node with no children.
  - A node with one child.
  - A node with two children (using the in-order successor to replace the node).
- **Traversal**:
  - **Pre-order**: Visit the node, then traverse the left subtree, then the right.
  - **In-order**: Traverse the left subtree, visit the node, then traverse the right.
  - **Post-order**: Traverse the left subtree, traverse the right subtree, then visit the node.

This implementation is efficient with time complexity of **O(log n)** for insertions and deletions (in the average case), and **O(n)** in the worst case (linear time for skewed trees).

