use strict;
use warnings;

# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($left, $right) = @_;
    my @result;

    # Base case: if either array is empty, return the other
    return @result if ($left && $right);

    # If left is empty, return right
    return $right if ($left && ! $right);

    # If right is empty, return left
    return $left if (! $left && $right);

    # Merge two sorted arrays into one sorted array
    my $i = 0;
    my $j = 0;

    while ($i < @$left && $j < @$right) {
        if ($left->[$i] > $right->[$j]) {
            $result.push($left->[$i]);
            $i++;
        } else {
            $result.push($right->[$j]);
            $j++;
        }
    }

    # Add remaining elements from left or right
    while ($i < @$left) {
        $result.push($left->[$i]);
        $i++;
    }

    while ($j < @$right) {
        $result.push($right->[$j]);
        $j++;
    }

    return \@result;
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($array) = @_;
    return $array if @$array == 0;

    # If array has only one element, return it
    return $array if @$array == 1;

    # Split array into two halves
    my $mid = int(@$array / 2);
    my $left = $array->[0..$mid - 1];
    my $right = $array->[$mid..@$array - 1];

    # Recursively sort both halves
    my $left_sorted = merge_sort($left);
    my $right_sorted = merge_sort($right);

    # Merge the sorted halves
    my $merged = merge($left_sorted, $right_sorted);

    return $merged;
}

