use strict;
use warnings;

# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($left, $right) = @_;
    my @merged;

    # Base cases
    if (!@$left) {
        return $right;
    }
    if (!@$right) {
        return $left;
    }

    # Compare the first elements of both arrays
    if ($left->[0] > $right->[0]) {
        push @merged, $left->[0];
        return [ @$left[1..-1] ] . merge( $left->[1..-1], $right );
    } else {
        push @merged, $right->[0];
        return [ @$right[1..-1] ] . merge( $left, $right->[1..-1] );
    }
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr <= 1;

    my $mid = @$arr / 2;
    my $left = [ @$arr[0..$mid - 1] ];
    my $right = [ @$arr[$mid..@$arr - 1] ];

    my $sorted_left = merge_sort($left);
    my $sorted_right = merge_sort($right);

    return merge($sorted_left, $sorted_right);
}

# Main program
sub main {
    print "Enter integers separated by spaces (end with 'exit'):\n";

    my @input;
    while (1) {
        chomp(my $line = <STDIN>);
        last if $line eq 'exit';

        my @elements = split(/\s+/, $line);
        foreach my $num (@elements) {
